What is the output?<br><pre><code>import numpy as np

# Sigmoid derivative property
def sigmoid(z):
    return 1 / (1 + np.exp(-z))

z_values = [0, 1, -1, 5, -5]
for z in z_values:
    s = sigmoid(z)
    deriv = s * (1 - s)
    print(f"z={z:2d}: sigmoid={s:.4f}, derivative={deriv:.4f}")</code></pre>
